  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "test": "vitest run",
    "watch": "tsc --watch"
  },
  "devDependencies": {
    "typescript": "^5.6.3",
    "vitest": "^2.1.4",
    "happy-dom": "^15.7.4"
  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts']
  }
});
{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "Bundler",
    "strict": true,
    "outDir": "wwwroot/dist",
    "rootDir": "src",
    "sourceMap": true,
    "lib": ["ES2022", "DOM", "DOM.Iterable"],
    "esModuleInterop": true,
    "forceConsistentCasingInFileNames": true,
    "skipLibCheck": true,
    "noEmitOnError": true
  },
  "include": ["src/**/*.ts"],
  "exclude": ["src/**/*.test.ts", "node_modules", "wwwroot"]
}

/**
 * Formatting helpers for the DTOs in `types.ts`.
 *
 * `types.ts` holds ONLY the DTO interfaces and no runtime code — these two
 * utilities live here instead.
 */

/**
 * Format a byte count as a human-readable string using 1024-based units.
 *
 * - Values < 1024 render as an integer byte count, e.g. `512 B`, `0 B`.
 * - Values >= 1024 render with up to one decimal place, stripping a trailing
 *   `.0`, e.g. 1024 -> "1 KB", 1536 -> "1.5 KB", 1048576 -> "1 MB".
 */
export function formatBytes(n: number): string {
    const units = ["B", "KB", "MB", "GB"];
    let unitIndex = 0;
    let value = n;

    while (value >= 1024 && unitIndex < units.length - 1) {
        value /= 1024;
        unitIndex++;
    }

    if (unitIndex === 0) {
        // Bytes — render as integer
        return `${Math.round(value)} ${units[unitIndex]}`;
    }

    // KiB or above — up to one decimal place, strip trailing .0
    const formatted = value.toFixed(1);
    const trimmed = formatted.endsWith(".0") ? formatted.slice(0, -2) : formatted;
    return `${trimmed} ${units[unitIndex]}`;
}

/**
 * Format an ISO 8601 date string as a localized date/time string.
 * Equivalent to `new Date(iso).toLocaleString()`.
 */
export function formatDate(iso: string): string {
    return new Date(iso).toLocaleString();
}

